parameters.jsCode:
const rows = $input.all();
const chatId = $('Normalize Input').first().json.chatId

// No saved materials
if (rows.length === 0) {
  return [{
    json: {
      chatId,
      empty: true
    }
  }];
}

// One button per material, one button per row in the keyboard
const buttons = rows.map(row => ([
  {
    text: row.json.title,
    callback_data: `pick:${row.json.id}`
  }
]));

return [{
  json: {
    chatId,
    empty: false,
    keyboard: JSON.stringify({ inline_keyboard: buttons }),
    count: rows.length
  }
}];

