const session = $('Prepare Session').first().json;
const chatId = session.chatId;
const questions = session.quiz.questions;
const q = questions[0];

const optionsText = ['A', 'B', 'C', 'D']
  .map(k => `*${k})* ${q.options[k]}`)
  .join('\n');

const text = `*Question 1/5*\n\n${q.question}\n\n${optionsText}`;

const buttons = [['A', 'B', 'C', 'D'].map(k => ({
  text: k,
  callback_data: `ans:${q.id}:${k}`
}))];

return [{
  json: {
    chatId,
    text,
    keyboard: JSON.stringify({ inline_keyboard: buttons })
  }
}];

const session = $input.first().json;
const { questionId, answer, chatId } = $('Parse Answer').first().json;

const questions = typeof session.questions === 'string'
  ? JSON.parse(session.questions)
  : session.questions;

let answers = [];
try {
  answers = typeof session.answers === 'string'
    ? JSON.parse(session.answers)
    : (session.answers || []);
} catch (e) {
  answers = [];
}

answers.push({ qid: questionId, answer });

const nextIdx = answers.length;
const done = nextIdx >= questions.length;

if (done) {
  let correct = 0;
  const feedback = [];
  for (const a of answers) {
    const q = questions.find(x => x.id === a.qid);
    if (!q) continue;
    const ok = q.correctAnswer === a.answer;
    if (ok) correct++;
    feedback.push({
      question: q.question,
      your: a.answer,
      yourText: q.options[a.answer],
      right: q.correctAnswer,
      rightText: q.options[q.correctAnswer],
      ok,
      explanation: q.explanation
    });
  }
  const score = Math.round(correct / questions.length * 100);
  return [{
    json: {
      chatId,
      done: true,
      score,
      correct,
      total: questions.length,
      feedback,
      materialId: session.materialId
    }
  }];
}

const next = questions[nextIdx];
const optionsText = ['A', 'B', 'C', 'D']
  .map(k => `*${k})* ${next.options[k]}`)
  .join('\n');

const buttons = [['A', 'B', 'C', 'D'].map(k => ({
  text: k,
  callback_data: `ans:${next.id}:${k}`
}))];

return [{
  json: {
    chatId,
    done: false,
    text: `*Question ${nextIdx + 1}/${questions.length}*\n\n${next.question}\n\n${optionsText}`,
    keyboard: JSON.stringify({ inline_keyboard: buttons }),
    updatedAnswers: JSON.stringify(answers),
    currentQ: nextIdx
  }
}];

const data = $input.first().json;
const { chatId, score, correct, total, feedback, materialId } = data;

const lines = feedback.map((f, i) => {
  const icon = f.ok ? '✅' : '❌';
  let line = `*Q${i + 1}* ${icon}\n${f.question}\nYour answer: ${f.your}) ${f.yourText}`;
  if (!f.ok) {
    line += `\nCorrect: ${f.right}) ${f.rightText}\n_${f.explanation}_`;
  }
  return line;
});

const emoji = score >= 80 ? '🏆' : score >= 60 ? '👍' : '📚';
const text =
  `${emoji} *Quiz complete!*\n` +
  `Score: *${score}%* (${correct}/${total})\n\n` +
  lines.join('\n\n') +
  `\n\nSend /quiz to try another topic.`;

return [{ json: { chatId, text, score, materialId } }];
